namespace sv_736b75ad8ad74b2ab751f7dfdc287f8d.Services;

public class WarehouseStateService
{
    private string _currentWarehouseId = "WH-001";

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        Warehouses.TryGetValue(_currentWarehouseId, out var name) ? name : _currentWarehouseId;

    public static readonly Dictionary<string, string> Warehouses = new()
    {
        ["WH-001"] = "Warehouse A – Main Distribution",
        ["WH-002"] = "Warehouse B – East Regional",
        ["WH-003"] = "Warehouse C – West Regional",
        ["WH-004"] = "Warehouse D – Cold Storage"
    };

    public event Func<Task>? OnChange;

    public async Task SetWarehouseAsync(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        if (OnChange is not null)
            await OnChange.Invoke();
    }
}

namespace sv_736b75ad8ad74b2ab751f7dfdc287f8d.Services;

public class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int CurrentLowStockCount { get; private set; }

    public event Func<Task>? OnAlertCountChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
    }

    /// <summary>Simulates a database query returning low-stock item count.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Call when a component that needs polling becomes active.
    /// Polling starts on the first subscriber and stops when the last unsubscribes.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            _ = PollLoopAsync(_cts.Token);
        }
    }

    /// <summary>
    /// Call when a component that needed polling is disposed / hidden.
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _cts?.Cancel();
            _timer?.Dispose();
            _cts?.Dispose();
            _timer = null;
            _cts = null;
        }
    }

    /// <summary>Forces an immediate refresh (e.g. after warehouse change).</summary>
    public async Task RefreshAsync()
    {
        CurrentLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire once immediately so UI has data right away.
        await RefreshAsync();

        while (_timer is not null && !ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer.WaitForNextTickAsync(ct)) break;
                await RefreshAsync();
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
    }
}

