@using sv_736b75ad8ad74b2ab751f7dfdc287f8d.Services
@rendermode InteractiveServer
@implements IDisposable
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService

<div class="d-flex align-items-center gap-2">
    <label class="text-white mb-0 small fw-semibold" for="warehouseSelect">Site:</label>
    <select id="warehouseSelect"
            class="form-select form-select-sm"
            style="width: auto; min-width: 220px;"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseStateService.Warehouses)
        {
            <option value="@wh.Key">@wh.Value</option>
        }
    </select>
</div>

@code {
    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString() ?? "WH-001";
        await WarehouseState.SetWarehouseAsync(newId);
        // Refresh alerts immediately for the new warehouse.
        await AlertService.RefreshAsync();
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleStateChange;
    }

    private async Task HandleStateChange()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleStateChange;
    }
}

@using sv_736b75ad8ad74b2ab751f7dfdc287f8d.Services
@rendermode InteractiveServer
@implements IDisposable
@inject InventoryAlertService AlertService

@if (AlertService.CurrentLowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@AlertService.CurrentLowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-auto">0</span>
}

@code {
    protected override void OnInitialized()
    {
        AlertService.OnAlertCountChanged += HandleAlertChanged;
    }

    private async Task HandleAlertChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= HandleAlertChanged;
    }
}

