@page "/dashboard"
@rendermode InteractiveServer
@using sv_736b75ad8ad74b2ab751f7dfdc287f8d.Services
@implements IDisposable
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService

<PageTitle>Dashboard – @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-header">
        <strong>@WarehouseState.CurrentWarehouseName</strong>
        <span class="text-muted ms-2">(@WarehouseState.CurrentWarehouseId)</span>
    </div>
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        @if (AlertService.CurrentLowStockCount > 0)
        {
            <div class="alert alert-warning d-flex align-items-center" role="alert">
                <strong class="me-2">⚠️ @AlertService.CurrentLowStockCount</strong>
                item(s) are below minimum stock levels.
            </div>
        }
        else
        {
            <div class="alert alert-success" role="alert">
                ✅ All items are above minimum stock levels.
            </div>
        }
        <p class="text-muted small mb-0">
            Auto-refreshes every 10 seconds. Last checked: @_lastRefresh.ToString("HH:mm:ss")
        </p>
    </div>
</div>

@code {
    private DateTime _lastRefresh = DateTime.Now;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleWarehouseChanged;
        AlertService.OnAlertCountChanged += HandleAlertChanged;

        // Start the polling loop; stops when this component is disposed.
        AlertService.StartPolling();
    }

    private async Task HandleWarehouseChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    private async Task HandleAlertChanged()
    {
        _lastRefresh = DateTime.Now;
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleWarehouseChanged;
        AlertService.OnAlertCountChanged -= HandleAlertChanged;
        AlertService.StopPolling();
    }
}

